/* ===============================
   STABLE PARALLAX + FADE BACKGROUND
   =============================== */

const images = [
  `${process.env.PUBLIC_URL}/bg/bg-1.jpg`,
  `${process.env.PUBLIC_URL}/bg/bg-2.jpg`,
  `${process.env.PUBLIC_URL}/bg/bg-3.jpg`,
];

let currentIndex = 0;
let transitioning = false;

const onScroll = () => {
  if (transitioning) return; // 🔒 freeze during transition

  const scrollY = window.scrollY;
  const maxScroll =
    document.body.scrollHeight - window.innerHeight;
  const progress = Math.min(scrollY / maxScroll, 1);

  /* -------------------------------
     Parallax movement
     ------------------------------- */
  const offset = scrollY * 0.12;
  document.documentElement.style.setProperty(
    '--bg-offset',
    `${offset}px`
  );

  /* -------------------------------
     Dark gradient strength
     ------------------------------- */
  const darkness = Math.min(0.75, 0.35 + progress * 0.5);
  document.documentElement.style.setProperty(
    '--bg-darkness',
    darkness.toFixed(2)
  );

  /* -------------------------------
     Image index calculation
     ------------------------------- */
  const segmentSize = 1 / images.length;
  const targetIndex = Math.min(
    images.length - 1,
    Math.floor(progress / segmentSize)
  );

  /* -------------------------------
     Controlled transition
     ------------------------------- */
  if (targetIndex !== currentIndex) {
    transitioning = true;

    document.documentElement.style.setProperty(
      '--bg-image-b',
      `url(${images[targetIndex]})`
    );

    // Fade current image out
    document.documentElement.style.setProperty('--bg-a-opacity', '0');
    document.documentElement.style.setProperty('--bg-b-opacity', '1');

    setTimeout(() => {
      // Commit next image as base
      document.documentElement.style.setProperty(
        '--bg-image-a',
        `url(${images[targetIndex]})`
      );
      document.documentElement.style.setProperty('--bg-a-opacity', '1');
      document.documentElement.style.setProperty('--bg-b-opacity', '0');

      currentIndex = targetIndex;

      // Allow scroll effects again
      transitioning = false;
    }, 700);
  }
};

window.addEventListener('scroll', onScroll, { passive: true });
onScroll();
